// WHO Child Growth Standards — LMS parametreleri (0–60 ay).
// Kaynak: WHO Child Growth Standards (who.int) LMS tabloları; ay-indeksli.
// 0–24 ay uzunluk (yatarak), 24–60 ay boy (ayakta); wt=kg, len/hc=cm.
// Otomatik üretildi — elle düzenleme. L,M,S ile persentil eğrisi ve
// bebeğin kendi persentili hesaplanır (bkz. who_growth.dart).

class WhoLms {
  final List<double> l;
  final List<double> m;
  final List<double> s;
  const WhoLms(this.l, this.m, this.s);
}

/// Çalışma-zamanı LMS tablosu — gömülü ([_whoLmsEmbedded]) ile başlar, API/cache
/// verisi gelince [applyWhoLms] ile değiştirilir. Tüketiciler (who_growth.dart)
/// bunu okur; offline'da gömülü kalır.
Map<String, WhoLms> whoLms = Map<String, WhoLms>.of(_whoLmsEmbedded);

/// API/cache yanıtından ([{key, l, m, s}, ...]) tabloyu güncelle. Gömülüden
/// kopyalanıp üzerine yazılır → eksik/bozuk seriye karşı sağlam.
void applyWhoLms(List<dynamic> data) {
  final next = Map<String, WhoLms>.of(_whoLmsEmbedded);
  for (final e in data) {
    if (e is! Map) continue;
    final key = e['key'] as String?;
    final l = (e['l'] as List?)?.map((x) => (x as num).toDouble()).toList();
    final m = (e['m'] as List?)?.map((x) => (x as num).toDouble()).toList();
    final s = (e['s'] as List?)?.map((x) => (x as num).toDouble()).toList();
    if (key != null && l != null && m != null && s != null) {
      next[key] = WhoLms(l, m, s);
    }
  }
  whoLms = next;
}

